module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output flag
);
    reg [31:0] res;
    assign r = res[31:0];
    assign zero = (res[31:0] == 32'b0);
    assign negative = res[31];
    assign flag = (aluc == SLT || aluc == SLTU) ? res[0] : 1'bz;
    always @(*) begin
        case (aluc)
            ADD: begin
                {carry, res[31:0]} = {a[31], a[31:0]} + {b[31], b[31:0]};
                overflow = (a[31] == b[31]) && (res[31] != a[31]);
            end
            ADDU: begin
                res[31:0] = a[31:0] + b[31:0];
                overflow = 1'b0;
            end
            SUB: begin
                {carry, res[31:0]} = {a[31], a[31:0]} - {b[31], b[31:0]};
                overflow = (a[31] != b[31]) && (res[31] != a[31]);
            end
            SUBU: begin
                res[31:0] = a[31:0] - b[31:0];
                overflow = 1'b0;
            end
            AND: res[31:0] = a[31:0] & b[31:0];
            OR: res[31:0] = a[31:0] | b[31:0];
            XOR: res[31:0] = a[31:0] ^ b[31:0];
            NOR: res[31:0] = ~(a[31:0] | b[31:0]);
            SLT: begin
                res[31:0] = (a[31:0] < b[31:0]) ? 32'b1 : 32'b0;
                overflow = 1'b0;
            end
            SLTU: begin
                res[31:0] = (a[31:0] < b[31:0]) ? 32'b1 : 32'b0;
                overflow = 1'b0;
            end
            SLL: res[31:0] = b[31:0] << a[4:0];
            SRL: res[31:0] = b[31:0] >> a[4:0];
            SRA: res[31:0] = b[31:0] >>> a[4:0];
            SLLV: res[31:0] = b[31:0] << a[4:0];
            SRLV: res[31:0] = b[31:0] >> a[4:0];
            SRAV: res[31:0] = b[31:0] >>> a[4:0];
            LUI: res[31:0] = {b[15:0], 16'b0};
            default: begin
                res[31:0] = 32'b0;
                carry = 1'b0;
                overflow = 1'b0;
            end
        endcase
    end
endmodule
